import{_ as d,o as e,c as r,a2 as a}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"董事长信 - 1984","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1984年/翻译.md","filePath":"01_letters/1984年/翻译.md"}'),p={name:"01_letters/1984年/翻译.md"};function n(l,t,s,o,i,h){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="董事长信-1984" tabindex="-1">董事长信 - 1984 <a class="header-anchor" href="#董事长信-1984" aria-label="Permalink to &quot;董事长信 - 1984&quot;">​</a></h1><p>1985年2月25日</p><p>致伯克希尔·哈撒韦公司全体股东：</p><p>1984年我们净值增长1.526亿美元，每股涨133美元，听起来不错，其实也就中等水平。经济收益必须和产生收益的资本对比着看。我们过去二十年账面价值复利增长22.1%（从1964年19.46美元到1984年1,108.77美元），1984年只涨了13.6%。</p><p>去年我们讨论过，每股内在 business 价值增长才是真正重要的经济衡量指标。但计算内在价值很主观，我们的情况，账面价值就是有用，但略微低估的 proxy。我判断，1984年内在 business 价值和账面价值增速差不多。</p><p>过去我用学术语气告诉你，不断膨胀的资本基数拉低了回报率。不幸的是，现在学术语气得让位给报告语气了，历史22%就是历史了。未来十年要每年赚15%（假设我们继续当前分红政策，后面信里还会说），我们总共需要赚39亿美元。做到这个需要几个大想法，小想法不行。我的合伙人查理·<a href="/04_people/查理·芒格.html">查理·芒格</a>和我现在还没这些想法，但我们经验就是，它们偶尔会冒出来。（这战略计划够直白吧？）</p><h2 id="报告收益来源" tabindex="-1">报告收益来源 <a class="header-anchor" href="#报告收益来源" aria-label="Permalink to &quot;报告收益来源&quot;">​</a></h2><p>下一页表格显示伯克希尔报告收益来源。1983年年中蓝筹合并后，很多 constituent 企业伯克希尔净持股变化了。因为这些变化，表格前两列最能衡量 underlying 业务表现。</p><p>任何业务主体异常资产出售带来的重大损益，都汇总到表格底部证券交易一行，不包含在营业收益中。（我们认为，已实现资本利得损失年度数字没意义，但多年累计已实现未实现利得损失非常重要。）</p><p>此外，商誉摊销不扣在具体业务头上，1983年我信附录讲过原因，所以单独列出来。</p><table tabindex="0"><thead><tr><th></th><th><strong>税前总收益</strong></th><th></th><th><strong>伯克希尔份额</strong></th><th></th></tr></thead><tbody><tr><td></td><td>1984</td><td>1983</td><td>1984</td><td>1983</td></tr><tr><td></td><td>(单位：千美元省略)</td><td></td><td></td><td></td></tr><tr><td><strong>营业收益：</strong></td><td></td><td></td><td></td><td></td></tr><tr><td><strong>保险集团：</strong></td><td></td><td></td><td></td><td></td></tr><tr><td>承保</td><td>$(48,060)</td><td>$(33,872)</td><td>$(48,060)</td><td>$(33,872)</td></tr><tr><td>净投资收益</td><td>68,903</td><td>43,810</td><td>68,903</td><td>43,810</td></tr><tr><td>水牛城新闻</td><td>27,328</td><td>19,352</td><td>27,328</td><td>16,547</td></tr><tr><td>内布拉斯加家具城(1)</td><td>14,511</td><td>3,812</td><td>11,609</td><td>3,049</td></tr><tr><td>喜诗糖果</td><td>26,644</td><td>27,411</td><td>26,644</td><td>24,526</td></tr><tr><td>联合零售</td><td>(1,072)</td><td>697</td><td>(1,072)</td><td>697</td></tr><tr><td>蓝筹印花母公司</td><td>(1,843)</td><td>(1,422)</td><td>(1,843)</td><td>(1,876)</td></tr><tr><td>互助储蓄贷款</td><td>1,456</td><td>(798)</td><td>1,166</td><td>(467)</td></tr><tr><td>精密钢铁</td><td>4,092</td><td>3,241</td><td>3,278</td><td>2,102</td></tr><tr><td>纺织</td><td>418</td><td>(100)</td><td>418</td><td>(100)</td></tr><tr><td>韦斯考金融母公司</td><td>9,777</td><td>7,493</td><td>7,831</td><td>4,844</td></tr><tr><td>商誉摊销</td><td>(1,434)</td><td>(1,434)</td><td>(1,434)</td><td>(1,434)</td></tr><tr><td>债务利息</td><td>(14,734)</td><td>(15,104)</td><td>(14,097)</td><td>(13,844)</td></tr><tr><td>股东指定捐赠</td><td>(3,179)</td><td>(3,066)</td><td>(3,179)</td><td>(3,066)</td></tr><tr><td>其他</td><td>4,932</td><td>4,932</td><td>4,529</td><td>4,529</td></tr><tr><td><strong>营业收益合计</strong></td><td>87,739</td><td>61,043</td><td>82,021</td><td>51,410</td></tr><tr><td>GEICO特别分红</td><td>(19,575)</td><td></td><td>(19,575)</td><td></td></tr><tr><td>通用食品特别分红</td><td>8,111</td><td></td><td>8,111</td><td></td></tr><tr><td>证券出售和异常资产出售</td><td>104,699</td><td>67,260</td><td>101,376</td><td>65,089</td></tr><tr><td><strong>所有主体总收益</strong></td><td>$200,549</td><td>$147,878</td><td>$191,293</td><td>$136,074</td></tr></tbody></table><p>(1) 1983年数字只包含10月到12月。<br> (2) 1984和1983不可比；1983年年中蓝筹印花合并，重大资产转移。</p><p>眼神好的股东注意到，GEICO特别分红金额和表格位置，和去年 presentation 变了。虽然它们重新分类减少了&quot;会计&quot;收益，变化完全是形式，不是实质。但变化背后故事挺有意思。</p><p>去年我们说过：(1) 1983年年中GEICO要约回购自己股票；(2) 我们同时签了书面合同，GEICO从其他股东回购总股份，我们按比例卖给GEICO同等数量；(3) 要约结束，我们交割了35万股，拿到2,100万美元现金，我们持有GEICO比例和之前完全一样；(4) 从经济实质来说，我们这笔交易本质就是分红，顶尖律所意见就是，比例赎回本质和分红差不多；(5) 税法逻辑上，这种比例赎回本质上相当于分红，因此我们拿到2,100万美元，公司之间股息税率只有6.9%；(6) 重要的是，我们拿到2,100万美元，远低于我们持有GEICO未分配累计盈利，因此从经济实质说，我们认为就是分红。</p><p>因为这笔交易重大不寻常，去年季报和年报我们都给你高亮了，也告诉了我们审计师毕马威。毕马威奥马哈办公室和复核的芝加哥合伙人都没反对我们按分红披露。</p><p>1984年，通用食品我们做了几乎一模一样交易，唯一区别：通用食品是在公开市场一段时间持续回购，GEICO是一次性要约。通用食品回购的时候，我们每天按比例卖，保持我们持股比例不变，还是提前签了书面合同。我们拿到2,184万美元现金，持股比例依然保持8.75%不变，拿到钱还是远低于我们买入后累计未分配盈利，经济本质还是分红。</p><p>这时候毕马威纽约所进来了，1984年末它说，它不同意毕马威奥马哈和芝加哥复核合伙人结论，纽约观点认为，GEICO和通用食品交易应该按伯克希尔卖股票算，不是分红收入。这种会计方法下，我们投资每家公司成本一部分冲减赎回付款，收益算资本利得，不算股息收入。这只是会计处理，不影响税务：毕马威也同意，税务上这些交易就是分红。</p><p>我们从经济实质和正确会计两方面都不同意纽约观点，但为了避免审计师有保留意见，我们这里采纳了毕马威1984年观点，1983年也重新表述了。但这一切对内在 business 价值没影响：我们在GEICO和通用食品持股比例不变，现金拿到了，税也交了，我们持仓市值和计税基础都没变。</p><p>今年我们又和通用食品签了合同，它们公开市场回购，我们同步卖，保持我们持股比例不变，这样能保证我们税务上依然按分红处理。我们也认为，经济本质就是创造分红收入，但会计准则没明确说之前，我们会计上还是按卖股票处理，不算分红。任何这种特殊交易我们未来都会给你显著披露。</p><p>我们很享受这些比例赎回低税务成本，也做了几笔，但我们认为，当优秀企业股价远低于内在价值的时候，回购对不卖的股东至少同样有利。我们支持回购，但只支持因为价格和价值错配做的回购，不包括绿票讹诈回购——这种做法我们觉得恶心讨厌。绿票讹诈交易里，两方个人得益，都是剥削无辜没参与第三方。玩家：(1) &quot;股东&quot;勒索者，股票证书墨迹还没干，就给管理层发最后通牒，要钱还是要命；(2) 内部人，不管谁出钱赶紧求和，只要钱不是自己出；(3) 股东，钱被(2)用来打发(1)。尘埃落定，勒索的 transient 股东就发表自由企业演讲，被勒索管理层发表公司最佳利益演讲，无辜股东站着不动，出钱买单。</p><p>我们持仓最大几家公司都经常在价格远低于价值的时候大幅回购。作为股东，我们觉得这太鼓舞人心，对我们太有利，两个重要原因，一个明显，一个微妙不那么好懂。</p><p><strong>明显原因</strong>：基本算术，内在价值每股远低于市价大额回购，立刻就能大幅提升每股价值。公司收购项目几乎从来做不到一块钱投入拿两块钱现值，回购做得到，太多案例，收购一块钱投入一块都拿不到。</p><p><strong>另一个好处不那么好精确衡量，但长期一样重要</strong>：当企业股价远低于内在价值，管理层回购，说明它站在股东这边，不是扩张管理版图，不伤害股东利益。看到这点，股东和潜在股东都会对未来回报预期更高，股价就会更接近内在价值。价格完全理性，投资者应该为管理层站在股东这边给更高溢价。</p><p>相反，如果管理层明明知道股价低估，还发新股稀释，或者用保留盈利买低回报项目，市场迟早会给正确折价，管理层行为说明它动机，市场会反应出来，嘴说没用，行动才是关键，久了市场肯定知道。</p><p>关键词是**&quot;证明&quot;**，管理层嘴上天天说&quot;最大化股东财富&quot;，行动却完全相反，市场会给正确定价。我们三大持仓GEICO、华盛顿邮报、通用食品，都大幅低价回购，股东利益显著提升，我们拿着非常舒服。埃克森我们第四大持仓，也明智积极回购，我们只是最近才建仓。这些公司管理层都关心股东利益，我们喜欢持有这样企业，优秀经济加上股东导向管理层。</p><p>下表是1984年末我们可交易股权净持仓，所有数字排除了韦斯考和内布拉斯加家具城少数股东权益。</p><table tabindex="0"><thead><tr><th>公司名称</th><th>持股数</th><th>成本（千美元省略）</th></tr></thead><tbody><tr><td>联合出版</td><td>690,975</td><td>3,516</td></tr><tr><td>美国广播公司</td><td>740,400</td><td>44,416</td></tr><tr><td>埃克森</td><td>3,895,710</td><td>173,401</td></tr><tr><td>通用食品</td><td>4,047,191</td><td>149,870</td></tr><tr><td>GEICO</td><td>6,850,000</td><td>45,713</td></tr><tr><td>Handy &amp; Harman</td><td>2,379,200</td><td>27,318</td></tr><tr><td>Interpublic</td><td>818,872</td><td>2,570</td></tr><tr><td>西北工业</td><td>555,949</td><td>26,581</td></tr><tr><td>时代公司</td><td>2,553,488</td><td>89,327</td></tr><tr><td>华盛顿邮报</td><td>1,868,600</td><td>10,628</td></tr><tr><td><strong>总计</strong></td><td></td><td><strong>573,340</strong></td></tr><tr><td>其他普通股持仓</td><td></td><td>11,634</td></tr><tr><td><strong>普通股总合计</strong></td><td></td><td><strong>584,974</strong></td></tr></tbody></table><p>现在找同时满足我们定性和定量（价格对价值）标准的股权投资，已经十几年没这么难了。我们努力不妥协标准，虽然什么都不做最难。一位英国19世纪政治家说过，19世纪英国伟大归功于&quot;明智无为&quot;政策。历史学家说好说，参与者做起来太难。</p><h2 id="内布拉斯加家具城" tabindex="-1">内布拉斯加家具城 <a class="header-anchor" href="#内布拉斯加家具城" aria-label="Permalink to &quot;内布拉斯加家具城&quot;">​</a></h2><p>去年我给你介绍了<a href="/04_people/B夫人.html">B夫人</a>（罗斯·<a href="/04_people/B夫人.html">B夫人</a>）和她全家，我说他们太棒了，我还是说轻了。再看了一年他们非凡才能和品格，我可以诚实说，我从来没见过哪个管理团队，无论是发挥还是品格，都比<a href="/04_people/B夫人.html">B夫人</a>家族更好。</p><p><a href="/04_people/B夫人.html">B夫人</a>，董事长，现在91岁，最近当地报纸引述她话说：&quot;我回家吃了睡，就这样，等天亮我好回去干活&quot;。<a href="/04_people/B夫人.html">B夫人</a>一周七天在店里，从开门待到关门，一天做的决策可能比大多数CEO一年都多（还都比大多数对）。</p><p>五月，纽约大学给<a href="/04_people/B夫人.html">B夫人</a>授予商业科学荣誉博士。（她真是快轨学生：拿到博士之前一辈子没进过一天教室。）之前NYU商业荣誉博士获得者包括埃克森CEO Clifton Garvin，花旗CEO Walter Wriston，IBM前CEO Frank Cary，通用汽车前CEO <a href="/search.html?q=Tom_Murphy">Tom_Murphy</a>，最近还有保罗·沃尔克。（他们可都是好人，<a href="/04_people/B夫人.html">B夫人</a>和他们站一起不丢人。）</p><p><a href="/04_people/B夫人.html">B夫人</a>家族血脉一点没稀释。<a href="/04_people/B夫人.html">B夫人</a>儿子Louie，还有他三个儿子Ron、Irv、Steve，所有人都全心全意为NFM惊人成功做贡献。年轻一代都上了最好的商学院——就是<a href="/04_people/B夫人.html">B夫人</a>和Louie开的那个，他们表现就能看出来训练多棒。</p><p>去年NFM净销售增长1,430万美元，总销售1.15亿美元，全部来自奥马哈单店。这绝对是美国单店家居销售最大规模，实际上，去年销售增长本身就比很多不错的成功商店总规模还大。这个成功 deserve 成功，我说一下为什么：</p><p>给你几个数字：美国最大独立专业家居零售商Levitz家具，1984财年10-K说，他们价格&quot;一般比传统家具店传统区域便宜&quot;。Levitz运营毛利率44.4%，就是说，顾客花100美元买货，Levitz进货成本55.6美元。NFM毛利率不到一半，大约只有20%多，NFM能做到低价，因为效率 exceptional：运营费用（工资、房租、广告等等）大约占销售16.5%，Levitz是35.6%。</p><p>我不是批评Levitz，它们运营管理也很好，但NFM运营 simply extraordinary（记住，这一切1937年<a href="/04_people/B夫人.html">B夫人</a>500美元投资开始）。通过 unmatched 效率和精明大批量采购，NFM能给顾客每年至少省3,000万美元，比一般商店买同样商品，这种节省让它不断扩大地理覆盖，增长远远超过奥马哈市场自然增长。</p><p>很多人问我，<a href="/04_people/B夫人.html">B夫人</a>家族做生意有什么秘密，其实没什么神秘：全家人(1) 投入热情精力，让富兰克林和霍雷肖·阿尔杰看起来像辍学生；(2) 用 extraordinary 现实感定义自己能力圈，不在能力圈外做事，果断决策能力圈内所有事；(3) 哪怕再诱人，不碰能力圈外项目；(4) 对所有打交道的人，永远 behavior 高尚。（<a href="/04_people/B夫人.html">B夫人</a>总结就是：&quot;低价卖，说实话&quot;。）</p><p>我们买90%股权的时候，对<a href="/04_people/B夫人.html">B夫人</a>和她全家诚实正直评估就是：NFM从来没做过审计，我们没要求盘点，没核对应收，没核产权，我们给<a href="/04_people/B夫人.html">B夫人</a>支票5,500万美元，她给我们她的话，这就是公平交换。你我真幸运，能和<a href="/04_people/B夫人.html">B夫人</a>家族合伙。</p><h2 id="喜诗糖果" tabindex="-1">喜诗糖果 <a class="header-anchor" href="#喜诗糖果" aria-label="Permalink to &quot;喜诗糖果&quot;">​</a></h2><p>下面是蓝筹印花1972年收购喜诗以来，我们通常的业绩 recap：</p><table tabindex="0"><thead><tr><th>年份（截止12月31日）</th><th>销售额（千美元）</th><th>税后营业利润（千美元）</th><th>销量（磅）</th><th>门店数量</th></tr></thead><tbody><tr><td>1984</td><td>135,946</td><td>13,380</td><td>24,759,000</td><td>2</td></tr><tr><td>1983 (53周)</td><td>133,531</td><td>13,699</td><td>24,651,000</td><td>2</td></tr><tr><td>1982</td><td>123,662</td><td>11,875</td><td>24,216,000</td><td>2</td></tr><tr><td>1981</td><td>112,578</td><td>10,779</td><td>24,052,000</td><td>1</td></tr><tr><td>1980</td><td>97,715</td><td>7,547</td><td>24,065,000</td><td>1</td></tr><tr><td>1979</td><td>87,314</td><td>6,330</td><td>23,985,000</td><td>1</td></tr><tr><td>1978</td><td>73,653</td><td>6,178</td><td>22,407,000</td><td>1</td></tr><tr><td>1977</td><td>62,886</td><td>6,154</td><td>20,921,000</td><td>1</td></tr><tr><td>1976 (53周)</td><td>56,333</td><td>5,569</td><td>20,553,000</td><td>1</td></tr><tr><td>1975</td><td>50,492</td><td>5,132</td><td>19,134,000</td><td>1</td></tr><tr><td>1974</td><td>41,248</td><td>3,021</td><td>17,883,000</td><td>1</td></tr><tr><td>1973</td><td>35,050</td><td>1,940</td><td>17,813,000</td><td>1</td></tr><tr><td>1972</td><td>31,337</td><td>2,083</td><td>16,954,000</td><td>1</td></tr></tbody></table><p>这个业绩不是大势好带来的，相反，盒装巧克力行业很多知名参与者这些年要么亏钱，要么微薄盈利。我们知道只有一家大 competitor 高盈利，成功来自 exceptional 产品加上 exceptional 经理查克·哈金斯。</p><p>1984年我们涨价幅度比近年小得多，每磅卖出实得5.49美元，只比1983年涨1.4%。幸运的是，我们成本控制取得不错进展，近年成本控制一直给我们带来问题。除了原材料，这部分我们控制不了，去年每磅成本只涨了2.2%。</p><p>我们成本控制问题近年来因为同店销量（按磅算，不是美元）温和下降恶化。近年来，每年总磅数保持大致不变，只能靠每年新增几家门店。这种更多门店拿到同样总销量，自然对每磅销售成本带来很大压力。1984年同店销量下降1.1%，因为新增门店，总销量增长0.6%（两个百分比都调整了1983年53周影响）。</p><p>喜诗业务季节性越来越强，圣诞前四周占全年销量40%，全年利润75%。复活节和情人节也不少，剩下时间基本就是熬。近年来，圣诞销量占比越来越重要，大订单和邮购也增长。需求集中在圣诞假期给管理带来很多问题，查克和他团队 exceptional 技能优雅处理好，我们从来不会在服务质量或产品质量妥协，大多数大竞争者做不到。</p><p>1985年我们会继续努力，保持每磅成本涨幅低于通胀。不过要成功，需要同店磅数停止下滑。1985年价格平均会比1984年涨6-7%，假设同店销量不变，利润应该温和增长。</p><h2 id="水牛城晚报" tabindex="-1">水牛城晚报 <a class="header-anchor" href="#水牛城晚报" aria-label="Permalink to &quot;水牛城晚报&quot;">​</a></h2><p>1984年新闻利润比我们预期高很多，和喜诗一样，成本控制取得出色进步。不包含新闻编辑室工时，总工时下降大约2.8%，生产力提升，总成本只涨4.9%。<a href="/04_people/斯坦·利普西.html">斯坦·利普西</a>和他管理团队这个 performance 是行业最好之一。</p><p>但我们现在成本加速上涨，1984年年中我们签了新的多年工会合同，工资大幅&quot;追赶&quot;上涨。这个追赶完全合理：我们1977-1982不盈利期间，工会合作精神帮我们保持成本竞争力，我们才能战胜Courier-Express。如果我们没控制住成本，那场斗争结果可能不一样。</p><p>因为新工会合同不同时间生效，1984年几乎没反映出追赶上涨，1985年几乎全部生效，所以我们单位人工成本今年涨幅会远远超过行业平均。我们预计生产力持续小幅提升抵消一部分，但没法避免今年人工成本显著上涨。新闻纸价格趋势现在也比1984差。主要就是这两个因素，我们预计新闻利润率至少小幅收缩。</p><p>对新闻业务有利两个重大经济因素： (1) 我们发行量对广告主特别有用，集中度异乎寻常高。&quot;区域&quot;报纸发行量范围大，另一方面，很大一部分发行量对大多数广告主没用，几百英里外订户对你分类广告卖小狗、对本地杂货卖东西都没 prospect。广告主说，&quot;浪费&quot;发行量伤害盈利能力：报纸成本很大程度由总发行量决定，但广告收入只对有用发行量敏感；(2) 我们在水牛城零售市场渗透率 exceptional，广告主只用我们就能触达几乎所有潜在顾客。</p><p>去年我告诉你，我们读者接受度 unusual，美国100大报纸，我们平日渗透率第一，周日第三。最新数字，平日渗透率我们第一，周日第二。（当然，水牛城家庭数量略微下降，所以我们平日发行量略微下降，周日没变。）</p><p>我还告诉你，我们一个主要原因就是读者不寻常接受度，因为我们给读者更多新闻，我们报纸新闻版面比例比我们这个规模任何主流报纸都高。1984年我们&quot;新闻洞&quot;比例50.9%，1983年50.4%，远远高于典型的35-40%。我们未来会继续保持这个比例在50%左右。我们也保持新闻就业，新闻工资涨9.1%，远远超过我们整体成本涨幅4.9%。</p><p>我们新闻洞政策花我们很多钱，因为多出来新闻版面要用更多新闻纸。所以我们新闻成本（新闻洞新闻纸加工资）占收入比例高于我们这个规模大多数主导报纸。但是，还有空间：我们这个规模主导报纸，高新闻成本和低新闻成本之间差可能三个百分点，税前利润率常常十个百分点，所以差别很大。</p><p>主导报纸经济学非常出色，商业世界最好之一。所有者自然愿意相信，他们出色盈利只能因为不断推出优秀产品。这个舒服理论在不舒服事实上站不住：一流报纸当然赚一流利润，三流报纸利润一样好甚至更好——只要社区里它一家独大。当然，产品质量对取得垄断地位很重要，我们相信水牛城新闻质量很重要，帮我们取得主导地位。一旦主导了，报纸自己决定好坏，劣质也能赚钱。大多数其他行业不是这样：差产品一定差经济结果。但报纸不一样，只要你垄断了，就算差，依然能赚钱，对大多数公民来说，报纸就是公告牌，本质必不可少。其他条件一样，质量高当然更好，但就算质量一般，也依然必不可少，依然能赚钱。</p><p>我们不会降低标准，管理层自己会强加高标准，我们对水牛城新闻投入高于平均新闻成本，代表我们定量标准，更重要定性标准。我们相信，<a href="/04_people/斯坦·利普西.html">斯坦·利普西</a>和Murray Light会继续应用高标准，查理和我相信，报纸是社会非常特殊机构，我们为水牛城新闻骄傲，未来几年我们打算让这份骄傲更配得上。</p><h2 id="保险运营" tabindex="-1">保险运营 <a class="header-anchor" href="#保险运营" aria-label="Permalink to &quot;保险运营&quot;">​</a></h2><p>下面是我们常用行业统计更新表格，两个关键指标：</p><table tabindex="0"><thead><tr><th style="text-align:center;">年份</th><th style="text-align:center;">保费写出年增长率(%)</th><th style="text-align:center;">保费赚得年增长率(%)</th><th style="text-align:center;">综合成本率（投保人分完后）</th></tr></thead><tbody><tr><td style="text-align:center;">1972</td><td style="text-align:center;">10.2</td><td style="text-align:center;">10.9</td><td style="text-align:center;">96.2</td></tr><tr><td style="text-align:center;">1973</td><td style="text-align:center;">8.0</td><td style="text-align:center;">8.8</td><td style="text-align:center;">99.2</td></tr><tr><td style="text-align:center;">1974</td><td style="text-align:center;">6.2</td><td style="text-align:center;">6.9</td><td style="text-align:center;">105.4</td></tr><tr><td style="text-align:center;">1975</td><td style="text-align:center;">11.0</td><td style="text-align:center;">9.6</td><td style="text-align:center;">107.9</td></tr><tr><td style="text-align:center;">1976</td><td style="text-align:center;">21.9</td><td style="text-align:center;">19.4</td><td style="text-align:center;">102.4</td></tr><tr><td style="text-align:center;">1977</td><td style="text-align:center;">19.8</td><td style="text-align:center;">20.5</td><td style="text-align:center;">97.2</td></tr><tr><td style="text-align:center;">1978</td><td style="text-align:center;">12.8</td><td style="text-align:center;">14.3</td><td style="text-align:center;">97.5</td></tr><tr><td style="text-align:center;">1979</td><td style="text-align:center;">10.3</td><td style="text-align:center;">10.4</td><td style="text-align:center;">100.6</td></tr><tr><td style="text-align:center;">1980</td><td style="text-align:center;">6.0</td><td style="text-align:center;">7.8</td><td style="text-align:center;">103.1</td></tr><tr><td style="text-align:center;">1981 (修正)</td><td style="text-align:center;">3.9</td><td style="text-align:center;">4.1</td><td style="text-align:center;">106.0</td></tr><tr><td style="text-align:center;">1982</td><td style="text-align:center;">4.4</td><td style="text-align:center;">4.5</td><td style="text-align:center;">109.7</td></tr><tr><td style="text-align:center;">1983 (修正)</td><td style="text-align:center;">4.5</td><td style="text-align:center;"></td><td style="text-align:center;">111.9</td></tr><tr><td style="text-align:center;">1984 (估计)</td><td style="text-align:center;">8.1</td><td style="text-align:center;"></td><td style="text-align:center;">117.7</td></tr></tbody></table><p>来源：Best行业平均</p><p>Best数据包含几乎整个行业，包括股份制、共同制、相互制保险公司。综合成本率代表总承保损失加费用对比保费收入；低于100表示承保盈利，高于100表示承保亏损。</p><p>很多年我们告诉过你，行业保费写出每年增长大约10%，才能让综合成本率大致保持不变。我们做这个假设，就是认为费用占保费比例保持大致稳定，因为业务量增长、通胀、司法判决不断扩大保单保障范围，所以损失每年大约增长10%。</p><p>我们这个观点证明让人失望：从1979年到1984年，保费增长总共才30%，如果每年增长10%，总增长应该是61%，1984年综合成本率应该和1979年100.6几乎一样，现在1984年已经117.7了。现在我们依然相信，承保盈利能力趋势关键指标就是行业保费写出年度同比变化百分比。现在看，1985年保费增长会远远超过10%，因此，假设灾难正常，我们预计年底综合成本率会开始下降。但在我们行业损失假设下——也就是每年增长10%——要把综合成本率拉回100，需要五年每年保费增长15%，意味着到1989年行业保费翻倍，我们觉得这个结果可能性很低。相反，我们预计保费增长会持续几年高于10%，之后竞争充分，综合成本率大概就在108-113之间。</p><p>我们1984年综合成本率让人汗颜，134。这是连续第三年，我们承保业绩远差于行业。我们预计1985年综合成本率会改善，我们改善幅度也会远远大于行业。Mike Goldberg接管保险运营后，修正了我之前犯的很多错误。而且，我们业务集中在过去几年结果比平均差很多的产品线，这种情况已经 subdued 很多竞争者，甚至消灭了一些，竞争者被削弱了，1984下半年我们某些重要产品线大幅涨价，业务流失很少。</p><p>有些年我告诉过你，总有一天，我们顶尖财务实力会真的改变我们保险运营竞争地位。这一天可能来了。我们几乎肯定是美国最强的财产险保险公司，资本头寸远远大于很多规模大得多的知名公司。同样重要，我们企业政策就是保持这个优势。</p><p>买家买保险，拿到的就是承诺，承诺价值必须用逆境可能性评估，不是顺境。最低程度，承诺必须看起来能经受住长期低迷股市加上非同寻常糟糕承保结果，我们保险子公司在任何这种环境下都愿意也能够兑现承诺，没几家其他公司能做到。</p><p>我们财务 strength 特别是在结构化 settlement 和损失准备金 assumption 业务特别有价值，我们去年报告过这个业务。结构化 settlement 索赔人，再保险公司承接损失准备金，都需要对几十年后能付钱完全放心，财产意外险领域没几家公司能满足这个测试。（说实话，我们自己再保险自己 liabilities，也只找屈指可数几家公司。）</p><p>我们这块新业务增长了，抵消负债需要的资金从1,620万美元增长到3,060万美元，我们预计增长会继续，可能大幅加速。为了支持这个预期增长，我们给哥伦比亚保险公司大幅增资，我们这个再保险子公司专门做结构化 settlement 和损失准备金 assumption。尽管这个业务竞争很激烈，回报应该还不错。</p><p>GEICO消息和往常一样，大部分都好。1984年主要保险业务单位增长出色，投资组合表现一直 extraordinary。尽管年底承保业绩恶化，依然远远好于行业平均。年底我们持股36%，所以我们拥有GEICO直接财产险保费8.85亿美元中3.2亿美元，是我们自己保费两倍多。</p><p>过去几年我报告过，GEICO股价表现远远超过公司 business 表现，虽然 business 本身已经很辉煌。那些年，我们资产负债表上GEICO投资账面价值增长速度超过GEICO内在 business 价值增长速度。我警告过你，股票每年表现都超过 business，不可能年年这样，有些年份股票表现一定会落后 business 业绩。1984年就发生了，我们GEICO权益内在 business 价值大幅增长，市值几乎没变。年初GEICO占伯克希尔净值27%，静态市值对我们全年增速影响很大。我们对这个结果完全不难受：我们宁愿GEICO business 价值一年涨X，市场下跌，也不愿意内在价值只涨二分之一X，市场飞涨。GEICO和我们所有投资一样，我们看 business 表现，不看市场表现，如果我们对 business 判断正确，市场最终会跟上。</p><p>你作为伯克希尔股东，从GEICO<a href="/04_people/杰克·伯恩.html">杰克·伯恩</a>、比尔·斯奈德、<a href="/04_people/卢·辛普森.html">卢·辛普森</a>三个人才那里获益非常多。GEICO核心业务——低成本汽车和房屋保险——有巨大可持续竞争优势，这在商业中很少见，金融服务业几乎不存在。（GEICO自己也证明，哪怕管理层优秀，核心业务之外也很难拿到超额盈利能力。）大行业里，GEICO这样竞争优势能带来非凡经济回报，杰克和比尔继续出色发挥潜力。</p><p>GEICO核心保险运营产生大部分资金，都交给卢投资，卢气质智力都 exceptional，长期投资产出色回报，风险还低于平均，绝对是保险行业最好投资经理。我非常赞赏感谢这三位杰出经理的努力和才能。</p><h2 id="损失准备金计提误差" tabindex="-1">损失准备金计提误差 <a class="header-anchor" href="#损失准备金计提误差" aria-label="Permalink to &quot;损失准备金计提误差&quot;">​</a></h2><p>任何持有财产险保险公司重要权益的股东，都应该懂，财产险公司当期盈利报告天生就有什么缺陷。菲尔·<a href="/04_people/本·格雷厄姆.html">本·格雷厄姆</a>，华盛顿邮报发行人，说日报是&quot;历史第一份草稿&quot;。不幸，财产险保险公司财务报表，最多也只能算盈利和财务状况第一份草稿，很多年之后才能改。</p><p>成本确定是主要问题，保险公司大部分成本来自当年保费收入对应的损失，很多损失当年不知道甚至不存在，很多损失发生几十年之后才能赔付。所以当年利润表 charge 的损失成本：(1) 当年发生当年赔付的损失；(2) 当年发生当年报告，但还没赔完的损失估计；(3) 当年发生没报告（叫IBNR——已发生未报告）损失估计；(4) 今年修正过去几年估计的净影响。</p><p>修正可能拖很久，最终，任何X年估计损失错了，一定要在修正年份改正，所以修正年份盈利也一定错了。比如，假设1979年一个被保险人受伤，我们估计赔1万美元，当年我们就 charge 1万损益，资产负债表负债端放1万准备金。如果1984年最终赔了10万美元，那1984年就要 charge 9万损失成本，这9万本来就是1979年费用，所以1984年盈利就错报了。</p><p>这种估计必然有误差，所以，哪怕管理层意图最正确，X年损失估计一定有误差，很多年后才能知道真相。因此，下表告诉你，这些年我们报告承保盈利，一年后我们根据现在知道的信息调整是什么样。我给你看这个，就是让你自己看看我们估计误差幅度多大，你也能看看我们是不是有系统性偏差，让你对我们现在未来数字提高警惕。</p><p>下表显示，我们近年报告承保结果，以及一年后我们&quot;现在知道了，回头看&quot;估计：</p><table tabindex="0"><thead><tr><th>年份</th><th>报告给你的承保结果</th><th>一年后经验调整修正数字</th></tr></thead><tbody><tr><td>1980</td><td>$ 6,738,000</td><td>$14,887,000</td></tr><tr><td>1981</td><td>$ 1,478,000</td><td>$ (1,118,000)</td></tr><tr><td>1982</td><td>$(21,462,000)</td><td>$(25,066,000)</td></tr><tr><td>1983</td><td>$(33,192,000)</td><td>$(50,974,000)</td></tr><tr><td>1984</td><td>$(45,413,000</td><td>?</td></tr></tbody></table><p>我们结构化 settlement 和损失准备金 assumption 业务不包含在这个表里，重要额外信息损失准备金经验看第43-45页。</p><p>帮你理解这个表格，给你解释一下最新数字：1984年报告税前承保损失4,540万美元，其中2,760万我们估计是1984年业务损失，加上1,780万是修正1983年估计增加损失。</p><p>你看了这个表就能知道，我报告给你的错的挺多，最近总是报告结果比真实情况好，这件事我特别懊恼，因为：(1) 我要是知道真实损失规模，我和保险经理行动一定会更紧急；(2) 我们多交了所得税，因为我们多报了盈利，把钱给了政府，我们不需要给，这些多交最终能找回来，但要等很久，我们拿不到利息。</p><p>因为我们业务偏向意外险和再保险，我们估计损失成本比专注产险的公司问题更大。（你给雇主承保，雇主厂房烧了，你很快就知道；雇主承保退休工人几十年后得了职业病，你几十年后才知道 total 成本。）但我们低估，自己在再保险领域经验最差，再保险客户也犯了和我们一样错误，我们基于客户信息做估计，他们错我们跟着错。</p><p>我最近听到一个故事，很适合我们保险会计问题：一个人出国旅行，父亲去世了，他接到姐姐电话，说父亲葬礼需要花钱，他说他马上回去，让姐姐先办，后来他又接到一个账单，15美元葬礼服装费，他付了，一个月后又收到15美元账单，又付了，再过一个月又收到15美元账单，他打电话问姐姐怎么回事，姐姐说：&quot;哦对了，我忘了告诉你，我们租了葬礼西装，父亲穿着租来西装下葬，所以账单来了分期付。&quot;</p><p>如果你做保险这些年，特别是再保险，这个故事扎心了。我们现在尽量把所有&quot;租西装&quot;负债都放进当前财报，但我们过去错误记录告诉你，你还是要对我们保持怀疑，我每年都会继续报告，误差不管正负，浮现出来我都会告诉你。</p><p>不是行业所有准备金误差都是无心之错。近年承保结果这么差，管理层有自由裁量权，人性弱点就出来了，一些弱势管理层面对弱势经营，就会用一些不好看会计手段掩盖真实情况。比如说，有些公司，如果真实评估损失，净值就可能低于负债， insolvent 了，但这种情况下，要 insolvent 公司自己主动申报死亡证明，现在就是这个&quot;荣誉体系&quot;，尸体自己申报，所以很多 &quot;walking dead&quot; 就是不申报，还继续拼命写业务，什么价格都接，就是为了 keep 现金进来，这种心态就像 embezzler 把钱赌光了，还想继续靠新钱补旧坑。只要不发生大灾难，它们一直能这么玩，哪怕已经资不抵债，现金还是能一直进，损失很久之后才赔，所以 insolvent 保险公司很久之后才会现金流枯竭。</p><p>当然，大多数企业，资不抵债就没现金了，保险不一样：保单一开始就收现金，损失很久之后才赔，所以资不抵债保险公司净值亏光很久了还能现金流不断。所以，这些&quot;walking dead&quot; 哪怕已经亏光了，还会加倍努力写业务，几乎任何价格风险都接，就为了 keep 现金进来。这种心态，就像 embezzler 把钱赌没了，希望下一把赢回来。就算不赢，管理者反正也没损失，大不了就是本来已经没了，还是那样。损失越积越多，股东最后买单，州保障基金还要评估，最后让稳健保险公司帮烂公司埋单，问题还会传染，如果监管不早点识别早点关闭，甚至可能引发连锁危机。现在监管在这方面进步很慢。</p><h2 id="华盛顿公共电力供应系统" tabindex="-1">华盛顿公共电力供应系统 <a class="header-anchor" href="#华盛顿公共电力供应系统" aria-label="Permalink to &quot;华盛顿公共电力供应系统&quot;">​</a></h2><p>从1983年10月到1984年6月，伯克希尔保险子公司不断大量买入华盛顿公共电力供应系统（WPPSS）1、2、3项目债券，WPPSS 4、5项目烂尾，1983年7月已经违约22亿美元债券，虽然1、2、3项目和4、5义务人不一样，但是4、5问题给1、2、3也带来很大不确定性，可能严重损害1、2、3信用，另外Bonneville电力管理局担保也有很多问题。</p><p>尽管这些重大负面，查理和我判断，我们买的价格，风险被盈利前景远远补偿了。你知道，我们保险买股票，就是用我们买整家企业标准买，这种 business 估值方法在专业 money manager 那里不流行，还被学术界嘲笑。简单说，我们觉得，如果我们能以商业企业整个收购价零头，买到不错 business 部分股权，长期肯定有好事发生，尤其是我们集中持有一批这样证券。</p><p>我们把这种 business 估值方法延伸到买债券，比如WPPSS。我们拿投资1.39亿美元买WPPSS债券，和投资1.39亿买一个运营企业对比。WPPSS这个&quot;business&quot;，合同承诺税后给我们2,270万美元利息，现在每年现金拿到，我们买价税后收益率16.3%，这样 unleveraged 盈利的运营企业，谈判收购要卖2.5-3亿美元（有时候还贵得多）。对一个我们理解、非常喜欢的 business，我们乐意花这个价格。但WPPSS债券我们拿到同样盈利只花了一半价格。</p><p>当然，WPPSS也有小风险，一两年内可能变得一文不值，也可能利息支付中断很长时间。再说，上行潜力最多就是我们持有的债券面值2.05亿美元，只比我们买价高48%，上行封顶是重要缺点。但是你要知道，大多数运营企业，除非不断再投资，上行潜力也有限，通胀条件下，大多数企业就算ROE不错，也没法自动提升回报，更多资本才能带来更多盈利。（举个债券当 business 例子：如果你买了30年12%零息债券，今天花1,000万美元买，2015年到期拿3亿美元。如果每年12%，你把利息再投资买更多同样债券，最终你也拿到3亿，和企业留存盈利再投资一样。）</p><p>我们这种债券投资方法——把债券当成特殊 business 看——可能看起来有点怪，但我们相信，如果投资者都用商人视角看债券，能避免很多大错。比如说，1946年，20年期AAA免税债券收益率不到1%，投资者买的时候，就是买一个&quot;business&quot;每年赚1%账面价值，永远没法更高，还花100美分买一块钱账面价值，就算你用 business 视角看，一眼就能看出这破生意不能买。那时候，优秀企业10%、12%、甚至15%税后ROE，就能按账面价值买，为什么要买这个？</p><p>但债券投资者买入这种收益率，高高兴兴签了二三十年，这种事当年还真发生了。那时候，就是因为大家习惯了债券投资思维，看不到本质，所以犯了错。这种错现在还会发生，只是不极端而已。</p><p>我们再强调一次，WPPSS投资确实有风险，风险很难评估。查理和我一辈子做50个类似决策，大概能对40多个，我们判断现在这个机会，期望收益挺不错，错了也不会对伯克希尔造成致命伤害。我们不对，我们也认了，但是大多数经理，没动力做这种聪明但有概率看起来像傻子的决策：做成了也就拍一下肩，做错了炒鱿鱼。我们不一样，查理和我占伯克希尔47%，我们不用担心被炒，我们拿伯克希尔钱就像拿自己钱，所以行为方式不一样，投资和管理都不走寻常路。</p><p>我们保险投资还是集中，WPPSS就是例子，只有财务特别强才能这么做，对几乎所有其他保险公司，这么集中都完全不合适。我们 exceptional 财务实力，才能让我们重仓少数我们仔细想过、便宜买的机会。（就像比利·罗斯说：&quot;你要是有四十个老婆，你哪个都没法真了解。&quot;）长期来看，我们集中政策应该能带来更好结果，当然肯定会有坏年份，但至少你知道，我们钱都是按我们和你一样的标准投的。</p><p>我们买WPPSS大部分在不同价格不同情况买的，现在如果我们变了立场，不会告诉你，买完卖完才会说。证券买卖就是竞争生意，就算一点点额外竞争，就能让我们多花很多钱买，所以我们不会对我们证券活动评论，对媒体、股东、任何人都不说，除非法律要求。WPPSS就是例子，1983年10月到1984年6月，我们尽可能多买1、2、3项目债券，我们只买了不到发行在外3%，再多来几个买家跟着我们买，我们买价就会显著上升，可能多花几百万，所以我们不会对我们证券活动说什么。</p><p>最后说一句WPPSS：大多数情况下我们不喜欢买大多数长期债券，近年也买得很少，因为我们认为债券就像美元，长期美元 outlook 黯淡。我们相信未来通胀大概率还会，我们不知道平均通胀到底多少，我们也认为，恶性通胀可能性不小，不能忽略，尽管现在通胀降下来了。现在财政政策巨额赤字，很难反转，（就像查理·布朗说的，政治家都信奉：&quot;没有什么问题大到你跑不掉解决不了。&quot;）不反转，高通胀可能推迟（也许很长时间），但不会消失。高通胀真的来了，全面通胀，分散股票组合也会巨亏真实价值，但债券亏得更多得多。所以我们认为，全债券组合有小但不能接受的&quot;清零&quot;风险，买长期债券必须过特别关卡，只有机会明显比其他更好才会买，这种机会很少。</p><h2 id="分红政策" tabindex="-1">分红政策 <a class="header-anchor" href="#分红政策" aria-label="Permalink to &quot;分红政策&quot;">​</a></h2><p>分红政策股东常常听报道，但很少有人解释。公司会说，&quot;我们目标分40-50%盈利，CPI涨了我们至少保持股息增长&quot;，然后就没了，为什么选这个政策不给分析。但资本配置对企业和投资管理都至关重要，所以我们觉得经理人和股东都应该好好想想，什么时候该留存，什么时候该分掉。</p><p>第一个要点要懂：不是所有盈利都一样，很多企业特别是高资产/利润比，通胀让很多报告盈利变成&quot;假&quot;，这些假盈利就是&quot;受限&quot;盈利，不能分，要是分了，企业就会失去竞争力，没法维持现有单位销量，没法维持长期竞争地位，没法维持财务 strength。不管分红多保守，不断分受限盈利，企业注定慢慢消失。所以，受限盈利对所有者很少有价值，实际上，哪怕未来分红，也经常要打很大折扣，说白了，企业不管盈利多差，都要留存，通胀逼的，这个过程就是一美元留存变成25美分市场价值，就像十年前联合爱迪生那样，当时监管政策惩罚性，导致公司股价跌到账面价值四分之一，每留存一美元就变成25美分。但尽管这种黄金变铅的过程，大多数盈利还是再投资不是分给股东，与此同时，纽约各个工地到处都能看到标语写着&quot;必须挖&quot;。</p><p>受限盈利我们今天不讨论，我们讲不受限盈利，这些盈利真的可以分，可以留存，管理层要选，我们认为，到底选哪个，应该从股东利益出发，只有当留存一美元预期能创造至少一美元市场价值，才应该留存。</p><p>举个例子，假设你持有一个无风险10% perpetual 债券，有个特别性质，每年你可以选拿10% coupon 现金，或者再投资买更多同样条款10%债券。长期无风险利率现在是5%，这种情况下你会选拿现金还是再投资？如果再投资，10%债券现在市场不到100块，所以你肯定拿现金。反过来，如果长期利率15%，你肯定再投资，不会拿现金，因为市场上10%再投资能拿到超过100块。这个例子对企业分红一样，逻辑完全一样，当然企业再投资回报率不像债券是合同确定，是波动的，所以我们只能估计，估计完了，逻辑很简单：如果预期平均未来回报率高于市场要求回报率，就留存，否则就分。</p><p>很多公司经理明明知道再投资回报率低，还是留存，这种情况很多，因为惯性，他们喜欢扩张帝国，不对，母公司CEO让子公司A分掉所有盈利，投到子公司B赚更高回报，这逻辑完全对，但母公司层面经理常常做不到，把留在自己公司低回报盈利分掉给股东，让股东投更好地方。</p><p>就像，一个多部门公司CEO，每个子公司都懂这个逻辑，会要求低回报子公司分红，把钱投给高回报子公司，为什么母公司股东就不一样呢？整个母公司CEO，低回报业务留存盈利，拿去投更低回报，这种情况太常见了，优秀核心业务不断赚很多钱，不断投给很差的其他收购，股东收益被稀释，核心业务优秀回报都被掩盖了。就算核心一直赚，错误资本配置依然伤害股东价值。如果我们这种情况不断发生，再怎么说核心业务出色，股东整体回报依然不好。</p><p>伯克希尔过去历史，留存盈利回报率一直超过市场，每一美元留存创造超过一美元市场价值，这种情况下，任何分红都违背股东利益，如果我们分了，我们现在肯定小很多。历史就是这样，我们过去就是把留存投到更好 business，克服了本来起点很差的问题。（起点就是伯克希尔原来就是纺织，多元化零售原来就是百货，蓝筹原来就是印花，现在这些核心业务规模都缩水了，只有我们把赚的钱投到更好 business，我们才有今天。）</p><p>我们预计未来回报依然会低于历史回报，但是只要我们估计留存一美元预期能创造超过一美元市场价值，我们就会继续留存所有盈利。什么时候我们觉得达不到，我们就会分掉所有不受限盈利。现在情况是，未来，我们留存盈利主要用来壮大保险企业资本，现在很多竞争者财务弱，行业保费很快会大幅增长，1985年可能超过150亿，1983年不到50亿，这种环境下，我们可能拿到很多好业务，所以前景比很多年前好很多。</p><h2 id="杂项" tabindex="-1">杂项 <a class="header-anchor" href="#杂项" aria-label="Permalink to &quot;杂项&quot;">​</a></h2><p>这里每年我都登个小广告找收购，1984年我们一个股东给我们介绍了一家完全符合我们所有测试的公司，我们立刻跟进，就差一点成了，最后没成。所以广告我再重复一遍，和去年一字不差：</p><p>我们偏好： (1) 大额收购（税后盈利至少500万美元）， (2) 展示出持续稳定盈利能力（未来预测我们没兴趣，扭转也没兴趣）， (3) 企业ROE好，负债很少甚至没有， (4) 管理层在位（我们没法提供）， (5) 业务简单（如果太多技术，我们理解不了）， (6) 报价明确（我们不想浪费大家时间，价格不知道就谈）。</p><p>我们不会做敌意收购，我们可以承诺完全保密，很快给答复（一般五分钟以内），偏好现金收购，但我们也考虑发股，只要我们收到的内在价值和我们给出的一样多。欢迎潜在卖家通过我们过去做过生意的人介绍我们，对合适 business 合适卖家，我们能给个好家。</p><p>1984年伯克希尔股东指定捐赠项目，合格股份参与率创记录97.2%，总共捐赠3,179,000美元，1,519家慈善机构收到了。我们年会代理材料会让你对要不要继续、什么每股水平投咨询票，我们没见过先例，管理层让股东对公司慈善政策投咨询票。你来投票，我们听你的。</p><p>我们敦促新股东读一下60-61页股东指定捐赠项目描述，如果你未来想参与，我们强烈敦促你立刻把股票登记在你自己真实所有者名下，不要&quot;街边&quot;名或者 nominee 名。1985年9月30日没登记在所有者名下，不能参加1985年项目。</p><p>年会1985年5月21日在奥马哈，我希望你来，很多年会浪费时间，股东经理都浪费。有时候因为管理层不愿意开口说实质，更多时候因为股东参与者只关心自己上台出风头，不是关心 business，所以质量越来越差，很多人 interested 自己，吓退了 interested business。伯克希尔年会不一样，参会人数每年增长一点，我们从来没遇到过愚蠢问题或者自我宣传评论，所有人都是认真问 business 问题，查理和我很高兴都回答，多久都愿意。（但我们没法其他时间回答书面电话问题，一个人一个问题，一年一次会议，对我们3000股东，这样才对。）只有什么问题不能说，就是可能让我们公司真金白银损失，我们证券活动就是主要例子。</p><p>我们一直在这里夸我们股东质量，来年会你自己看看为什么，城外的人可以顺路逛内布拉斯加家具城，你买点东西，省下来的钱足够你路费，你还会享受这个体验。</p><p><strong>后续事件</strong>：这篇报告打出来给打字员一周后，生产前一周，我们同意以每股172.50美元买首都城市通信300万股，我们收购取决于首都城市收购美国广播公司，交易完成要1985年底很晚。我们很多年前年报就说过，我们欣赏汤姆·<a href="/search.html?q=Tom_Mur菲">Tom_Mur菲</a>和丹·伯克管理的首都城市，能力和诚信都是顶级。简单说，他们就是第一，我们未来年报会再说这个投资。</p><p>沃伦·E·<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，董事长<br> 董事会主席</p>',117)])])}const g=d(p,[["render",n]]);export{c as __pageData,g as default};
